package com.example.documentviewer;

import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

public class DocumentViewerActivity extends AppCompatActivity {

    private TextView documentInfoTextView;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_document_viewer);

        documentInfoTextView = findViewById(R.id.document_info_text_view);

        handleIntent(getIntent());
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent);
        handleIntent(intent);
    }

    private void handleIntent(Intent intent) {
        if (intent != null && Intent.ACTION_VIEW.equals(intent.getAction())) {
            Uri documentUri = intent.getData();
            String mimeType = intent.getType();

            if (documentUri != null) {
                String info = "Document URI: " + documentUri.toString() + "\n";
                info += "MIME Type: " + (mimeType != null ? mimeType : "Unknown");
                documentInfoTextView.setText(info);

                Toast.makeText(this, "Opening: " + (documentUri.getLastPathSegment() != null ? documentUri.getLastPathSegment() : "document"), Toast.LENGTH_LONG).show();

                // TODO: Implement actual document display logic here
                // For example:
                // if (mimeType != null && mimeType.startsWith("image/")) {
                //     // Load image into an ImageView
                // } else if ("application/pdf".equals(mimeType)) {
                //     // Use a PDF rendering library
                // } else {
                //     Toast.makeText(this, "Unsupported document type: " + mimeType, Toast.LENGTH_LONG).show();
                // }

            } else {
                documentInfoTextView.setText("No document URI found in the intent.");
                Toast.makeText(this, "Error: No document URI provided.", Toast.LENGTH_SHORT).show();
            }
        } else {
            documentInfoTextView.setText("This activity is configured to open documents via ACTION_VIEW intents.");
            Toast.makeText(this, "No valid VIEW intent received.", Toast.LENGTH_LONG).show();
        }
    }
}